#ifndef KERNEL_H
#define KERNEL_H

#include <ap_int.h>
#include <ap_fixed.h>
#include <hls_math.h>

// Project configuration
#define MATRIX_SIZE 10
#define TOTAL_BITS 46
#define FRAC_BITS 14
#define MAX_ITERATIONS 2000
#define CONVERGENCE_THRESHOLD 1e-8

// Total matrix elements
#define MATRIX_ELEMENTS (MATRIX_SIZE * MATRIX_SIZE)

// Fixed-point type for matrix elements
// Using Q46.14 format (46 total bits, 14 fractional bits)
typedef ap_fixed<TOTAL_BITS, TOTAL_BITS - FRAC_BITS, AP_RND, AP_SAT> fixed_t;

// Complex number structure
struct complex_t {
    fixed_t re;
    fixed_t im;

    complex_t() : re(0), im(0) {}
    complex_t(fixed_t r, fixed_t i) : re(r), im(i) {}
};

// Complex arithmetic operations
inline complex_t complex_add(complex_t a, complex_t b) {
    complex_t result;
    result.re = a.re + b.re;
    result.im = a.im + b.im;
    return result;
}

inline complex_t complex_sub(complex_t a, complex_t b) {
    complex_t result;
    result.re = a.re - b.re;
    result.im = a.im - b.im;
    return result;
}

inline complex_t complex_mul(complex_t a, complex_t b) {
    complex_t result;
    // (a + bi)(c + di) = (ac - bd) + (ad + bc)i
    result.re = a.re * b.re - a.im * b.im;
    result.im = a.re * b.im + a.im * b.re;
    return result;
}

inline complex_t complex_conj(complex_t a) {
    complex_t result;
    result.re = a.re;
    result.im = -a.im;
    return result;
}

inline fixed_t complex_abs(complex_t a) {
    // |a + bi| = sqrt(a^2 + b^2)
    fixed_t re2 = a.re * a.re;
    fixed_t im2 = a.im * a.im;
    fixed_t sum = re2 + im2;
    return hls::sqrt(sum);
}

inline fixed_t complex_angle(complex_t a) {
    // angle = atan2(im, re)
    return hls::atan2(a.im, a.re);
}

// Top-level kernel function
void kernel_top(
    const fixed_t matrix_real_in[MATRIX_ELEMENTS],
    const fixed_t matrix_imag_in[MATRIX_ELEMENTS],
    fixed_t eigenvalues_real_out[MATRIX_SIZE],
    fixed_t eigenvalues_imag_out[MATRIX_SIZE],
    fixed_t eigenvectors_real_out[MATRIX_ELEMENTS],
    fixed_t eigenvectors_imag_out[MATRIX_ELEMENTS],
    int &iter_count,
    int &cycles
);

#endif // KERNEL_H

#include "kernel.h"
#include <hls_stream.h>

// Helper function to get matrix element index
inline int mat_idx(int i, int j) {
    return i * MATRIX_SIZE + j;
}

// Helper to compute rotation matrix and apply Jacobi rotation
void apply_jacobi_rotation(
    complex_t A[MATRIX_SIZE][MATRIX_SIZE],
    complex_t V[MATRIX_SIZE][MATRIX_SIZE],
    int p, int q
) {
    // Get matrix elements
    complex_t a_pp = A[p][p];
    complex_t a_qq = A[q][q];
    complex_t a_pq = A[p][q];

    // Hermitian matrices have real diagonal elements
    fixed_t a_pp_real = a_pp.re;
    fixed_t a_qq_real = a_qq.re;

    // Calculate rotation angle theta
    fixed_t abs_a_pq = complex_abs(a_pq);
    fixed_t denom = a_pp_real - a_qq_real;

    fixed_t theta;
    if (hls::abs(denom) < fixed_t(1e-10)) {
        theta = fixed_t(0.7853981633974483); // pi/4
    } else {
        theta = fixed_t(0.5) * hls::atan((fixed_t(2.0) * abs_a_pq) / denom);
    }

    // Calculate phase angle phi
    fixed_t phi = -complex_angle(a_pq);

    // Compute rotation matrix elements
    fixed_t cos_theta = hls::cos(theta);
    fixed_t sin_theta = hls::sin(theta);
    fixed_t cos_phi = hls::cos(phi);
    fixed_t sin_phi = hls::sin(phi);

    // U[p,p] = cos(theta)
    complex_t u_pp(cos_theta, fixed_t(0));
    // U[p,q] = sin(theta) * exp(-i*phi) = sin(theta) * (cos(phi) - i*sin(phi))
    complex_t u_pq(sin_theta * cos_phi, -sin_theta * sin_phi);
    // U[q,p] = sin(theta) * exp(i*phi) = sin(theta) * (cos(phi) + i*sin(phi))
    complex_t u_qp(sin_theta * cos_phi, sin_theta * sin_phi);
    // U[q,q] = cos(theta) (corrected from reference bug)
    complex_t u_qq(cos_theta, fixed_t(0));

    // Temporary storage for transformed rows/cols
    complex_t A_temp[MATRIX_SIZE][MATRIX_SIZE];
    complex_t V_temp[MATRIX_SIZE][MATRIX_SIZE];

    // Copy A to A_temp
    COPY_A_LOOP_I: for (int i = 0; i < MATRIX_SIZE; i++) {
        COPY_A_LOOP_J: for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            A_temp[i][j] = A[i][j];
        }
    }

    // Apply left multiplication: A = U^H @ A
    // Only rows p and q are affected
    LEFT_MUL_COL: for (int j = 0; j < MATRIX_SIZE; j++) {
        #pragma HLS PIPELINE II=1
        complex_t a_pj = A_temp[p][j];
        complex_t a_qj = A_temp[q][j];

        // New row p = conj(u_pp) * old_row_p + conj(u_qp) * old_row_q
        complex_t u_pp_conj = complex_conj(u_pp);
        complex_t u_qp_conj = complex_conj(u_qp);
        A[p][j] = complex_add(complex_mul(u_pp_conj, a_pj), complex_mul(u_qp_conj, a_qj));

        // New row q = conj(u_pq) * old_row_p + conj(u_qq) * old_row_q
        complex_t u_pq_conj = complex_conj(u_pq);
        complex_t u_qq_conj = complex_conj(u_qq);
        A[q][j] = complex_add(complex_mul(u_pq_conj, a_pj), complex_mul(u_qq_conj, a_qj));
    }

    // Copy updated A to A_temp for right multiplication
    COPY_A2_LOOP_I: for (int i = 0; i < MATRIX_SIZE; i++) {
        COPY_A2_LOOP_J: for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            A_temp[i][j] = A[i][j];
        }
    }

    // Apply right multiplication: A = A @ U
    // Only columns p and q are affected
    RIGHT_MUL_ROW: for (int i = 0; i < MATRIX_SIZE; i++) {
        #pragma HLS PIPELINE II=1
        complex_t a_ip = A_temp[i][p];
        complex_t a_iq = A_temp[i][q];

        // New col p = old_col_p * u_pp + old_col_q * u_qp
        A[i][p] = complex_add(complex_mul(a_ip, u_pp), complex_mul(a_iq, u_qp));

        // New col q = old_col_p * u_pq + old_col_q * u_qq
        A[i][q] = complex_add(complex_mul(a_ip, u_pq), complex_mul(a_iq, u_qq));
    }

    // Zero out off-diagonal elements (p,q) and (q,p)
    A[p][q].re = fixed_t(0);
    A[p][q].im = fixed_t(0);
    A[q][p].re = fixed_t(0);
    A[q][p].im = fixed_t(0);

    // Update eigenvector matrix: V = V @ U
    // Copy V to V_temp
    COPY_V_LOOP_I: for (int i = 0; i < MATRIX_SIZE; i++) {
        COPY_V_LOOP_J: for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            V_temp[i][j] = V[i][j];
        }
    }

    // Update columns p and q of V
    UPDATE_V_ROW: for (int i = 0; i < MATRIX_SIZE; i++) {
        #pragma HLS PIPELINE II=1
        complex_t v_ip = V_temp[i][p];
        complex_t v_iq = V_temp[i][q];

        // New col p = old_col_p * u_pp + old_col_q * u_qp
        V[i][p] = complex_add(complex_mul(v_ip, u_pp), complex_mul(v_iq, u_qp));

        // New col q = old_col_p * u_pq + old_col_q * u_qq
        V[i][q] = complex_add(complex_mul(v_ip, u_pq), complex_mul(v_iq, u_qq));
    }
}

void kernel_top(
    const fixed_t matrix_real_in[MATRIX_ELEMENTS],
    const fixed_t matrix_imag_in[MATRIX_ELEMENTS],
    fixed_t eigenvalues_real_out[MATRIX_SIZE],
    fixed_t eigenvalues_imag_out[MATRIX_SIZE],
    fixed_t eigenvectors_real_out[MATRIX_ELEMENTS],
    fixed_t eigenvectors_imag_out[MATRIX_ELEMENTS],
    int &iter_count,
    int &cycles
) {
    #pragma HLS INTERFACE mode=m_axi port=matrix_real_in bundle=gmem0
    #pragma HLS INTERFACE mode=m_axi port=matrix_imag_in bundle=gmem1
    #pragma HLS INTERFACE mode=m_axi port=eigenvalues_real_out bundle=gmem2
    #pragma HLS INTERFACE mode=m_axi port=eigenvalues_imag_out bundle=gmem3
    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_real_out bundle=gmem4
    #pragma HLS INTERFACE mode=m_axi port=eigenvectors_imag_out bundle=gmem5
    #pragma HLS INTERFACE mode=s_axilite port=iter_count
    #pragma HLS INTERFACE mode=s_axilite port=cycles
    #pragma HLS INTERFACE mode=s_axilite port=return

    // Local storage for matrices
    complex_t A[MATRIX_SIZE][MATRIX_SIZE];
    complex_t V[MATRIX_SIZE][MATRIX_SIZE];

    #pragma HLS ARRAY_PARTITION variable=A dim=0 complete
    #pragma HLS ARRAY_PARTITION variable=V dim=0 complete

    // Load input matrix
    LOAD_MATRIX_I: for (int i = 0; i < MATRIX_SIZE; i++) {
        LOAD_MATRIX_J: for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            int idx = mat_idx(i, j);
            A[i][j].re = matrix_real_in[idx];
            A[i][j].im = matrix_imag_in[idx];
        }
    }

    // Initialize eigenvector matrix to identity
    INIT_V_I: for (int i = 0; i < MATRIX_SIZE; i++) {
        INIT_V_J: for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            if (i == j) {
                V[i][j].re = fixed_t(1.0);
                V[i][j].im = fixed_t(0);
            } else {
                V[i][j].re = fixed_t(0);
                V[i][j].im = fixed_t(0);
            }
        }
    }

    int iteration = 0;

    // Jacobi iteration loop
    JACOBI_ITER: for (int z = 0; z < MAX_ITERATIONS; z++) {
        // Find maximum off-diagonal element
        fixed_t off_diag_max = fixed_t(0);
        int max_p = 0;
        int max_q = 1;

        FIND_MAX_I: for (int i = 0; i < MATRIX_SIZE; i++) {
            FIND_MAX_J: for (int j = i + 1; j < MATRIX_SIZE; j++) {
                #pragma HLS PIPELINE II=1
                fixed_t abs_val = complex_abs(A[i][j]);
                if (abs_val > off_diag_max) {
                    off_diag_max = abs_val;
                    max_p = i;
                    max_q = j;
                }
            }
        }

        iteration = z;

        // Check convergence
        if (off_diag_max < fixed_t(CONVERGENCE_THRESHOLD)) {
            break;
        }

        // Apply Jacobi rotation
        apply_jacobi_rotation(A, V, max_p, max_q);
    }

    // Extract eigenvalues (diagonal of A) and write outputs
    WRITE_EIGENVALS: for (int i = 0; i < MATRIX_SIZE; i++) {
        #pragma HLS PIPELINE II=1
        eigenvalues_real_out[i] = A[i][i].re;
        eigenvalues_imag_out[i] = A[i][i].im;
    }

    // Write eigenvector matrix
    WRITE_EIGENVECS_I: for (int i = 0; i < MATRIX_SIZE; i++) {
        WRITE_EIGENVECS_J: for (int j = 0; j < MATRIX_SIZE; j++) {
            #pragma HLS PIPELINE II=1
            int idx = mat_idx(i, j);
            eigenvectors_real_out[idx] = V[i][j].re;
            eigenvectors_imag_out[idx] = V[i][j].im;
        }
    }

    // Set output metadata
    iter_count = iteration + 1;
    cycles = 0; // Will be measured by testbench
}
